package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope;

import static org.assertj.core.api.Assertions.assertThat;

import java.lang.reflect.Method;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.Dataset;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.Projection;
import org.eclipse.rdf4j.query.algebra.ProjectionElem;
import org.eclipse.rdf4j.query.algebra.ProjectionElemList;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.ContextAwareQueryOptimizer;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.FilterOptimizer;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.ProjectionRemovalOptimizer;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.QueryJoinOptimizer;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.QueryModelNormalizerOptimizer;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.UnionScopeChangeOptimizer;
import org.junit.jupiter.api.Test;

public class ContextAwareOptimizerIntegrationTest {

	@Test
	public void filterOptimizerUsesProofsInEnforceAndKeepsOffFactFree() throws Exception {
		FilterOptimizer optimizer = new FilterOptimizer(null, false, false);
		assertThat(optimizer).isInstanceOf(ContextAwareQueryOptimizer.class);

		QueryRoot enforceRoot = filteredJoin();
		try (OptimizationSession session = session(enforceRoot, ScopeSafetyMode.ENFORCE)) {
			optimize(optimizer, enforceRoot, session);
			assertThat(enforceRoot.getArg()).isInstanceOf(Join.class);
			assertThat(session.hasAnalysis()).isTrue();
		}

		QueryRoot offRoot = filteredJoin();
		try (OptimizationSession session = session(offRoot, ScopeSafetyMode.OFF)) {
			optimize(optimizer, offRoot, session);
			assertThat(session.hasAnalysis()).isFalse();
		}
	}

	@Test
	public void projectionRemovalUsesTheSameModeContract() throws Exception {
		ProjectionRemovalOptimizer optimizer = new ProjectionRemovalOptimizer();
		assertThat(optimizer).isInstanceOf(ContextAwareQueryOptimizer.class);
		Projection projection = new Projection(pattern("x", "y"),
				new ProjectionElemList(new ProjectionElem("x"), new ProjectionElem("y")), false);
		QueryRoot root = new QueryRoot(projection);
		try (OptimizationSession session = session(root, ScopeSafetyMode.ENFORCE)) {
			optimize(optimizer, root, session);
			assertThat(root.getArg()).isInstanceOf(StatementPattern.class);
			assertThat(session.hasAnalysis()).isTrue();
		}
	}

	@Test
	public void remainingStandardMutationIslandsExposeContextAwareEntryPoints() throws Exception {
		assertThat(new UnionScopeChangeOptimizer()).isInstanceOf(ContextAwareQueryOptimizer.class);
		assertThat(new QueryModelNormalizerOptimizer()).isInstanceOf(ContextAwareQueryOptimizer.class);
		assertThat(new QueryJoinOptimizer(new EvaluationStatistics())).isInstanceOf(ContextAwareQueryOptimizer.class);

		Join directional = new Join(pattern("shared", "provided"),
				new Filter(pattern("shared", "right"), Var.of("provided")));
		QueryRoot root = new QueryRoot(directional);
		QueryJoinOptimizer optimizer = new QueryJoinOptimizer(new EvaluationStatistics());
		try (OptimizationSession session = session(root, ScopeSafetyMode.ENFORCE)) {
			optimize(optimizer, root, session);
			assertThat(root.getArg()).isSameAs(directional);
			assertThat(session.hasAnalysis()).isFalse();
		}
	}

	private static void optimize(Object optimizer, TupleExpr root, OptimizationSession session) throws Exception {
		Method method = optimizer.getClass()
				.getMethod("optimize", TupleExpr.class, Dataset.class, BindingSet.class,
						OptimizationSession.class);
		method.invoke(optimizer, root, null, null, session);
	}

	private static OptimizationSession session(TupleExpr root, ScopeSafetyMode mode) {
		return OptimizationSession.open(root, null, null,
				new ScopeSafetyConfiguration(mode, 8, 0, false, 0.0, 10_000));
	}

	private static QueryRoot filteredJoin() {
		return new QueryRoot(new Filter(
				new Join(pattern("shared", "leftOnly"), pattern("shared", "rightOnly")),
				Var.of("leftOnly")));
	}

	private static StatementPattern pattern(String first, String second) {
		return new StatementPattern(Var.of(first),
				Var.of("_p", SimpleValueFactory.getInstance().createIRI("urn:p")), Var.of(second));
	}
}
